create extension if not exists pgcrypto;
create table if not exists profiles (id uuid primary key references auth.users(id) on delete cascade, email text, display_name text, role text default 'user', created_at timestamptz default now());
create table if not exists portfolios (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, base_currency text default 'EUR', settings_json jsonb default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists roboadvisors (id uuid primary key default gen_random_uuid(), portfolio_id uuid not null references portfolios(id) on delete cascade, name text not null, entity_name text, amount_invested_total numeric default 0, composition_json jsonb default '[]'::jsonb, updated_at timestamptz default now());
create table if not exists holdings (id uuid primary key default gen_random_uuid(), portfolio_id uuid not null references portfolios(id) on delete cascade, isin text not null, fund_name text not null, manager text, entity_name text, contract_mode text not null check (contract_mode in ('individual','roboadvisor')), roboadvisor_id uuid references roboadvisors(id) on delete set null, shares numeric default 0, amount_invested numeric default 0, classification_json jsonb default '{}'::jsonb, pricing_json jsonb default '{}'::jsonb, source_json jsonb default '{}'::jsonb, metadata_json jsonb default '{}'::jsonb, updated_at timestamptz default now());
alter table profiles enable row level security; alter table portfolios enable row level security; alter table roboadvisors enable row level security; alter table holdings enable row level security;
create policy "profiles_select_own" on profiles for select using (auth.uid() = id); create policy "profiles_upsert_own" on profiles for all using (auth.uid() = id) with check (auth.uid() = id);
create policy "portfolios_own" on portfolios for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
create policy "roboadvisors_own" on roboadvisors for all using (exists(select 1 from portfolios p where p.id = portfolio_id and p.user_id = auth.uid())) with check (exists(select 1 from portfolios p where p.id = portfolio_id and p.user_id = auth.uid()));
create policy "holdings_own" on holdings for all using (exists(select 1 from portfolios p where p.id = portfolio_id and p.user_id = auth.uid())) with check (exists(select 1 from portfolios p where p.id = portfolio_id and p.user_id = auth.uid()));
create or replace function public.handle_new_user() returns trigger language plpgsql security definer as $$ begin insert into public.profiles (id, email) values (new.id, new.email) on conflict (id) do nothing; return new; end; $$;
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
